import numpy as np
import pandas as pd

# ❌ Slow way (iteration)
df = pd.DataFrame({'score': [85, 92, 78, 95, 70]})

def calculate_grade(row):
    if row['score'] > 90:
        return 'A'
    elif row['score'] > 80:
        return 'B'
    elif row['score'] > 70:
        return 'C'
    else:
        return 'F'

df['grade'] = df.apply(calculate_grade, axis=1)  # Slow
